public void insert()
{
    Inventtransferline                  inventtransferline;
    InventTransferParmLine              inventTransferParmLine;
    ETG_TransferOrderQualitySpec        transferOrderQualitySpec, transferOrderQualitySpecloc, transferOrderQualitySpecinventtransId;
    ETG_QualitySubGrpView               qualitySubGrpView;



    //select firstonly inventtransferline where inventtransferline.InventTransId == this.InventTransId;
    select firstonly transferOrderQualitySpecinventtransId where transferOrderQualitySpecinventtransId.InventTransId == this.InventTransId;


    if (transferOrderQualitySpecinventtransId.InventTransId == '')
    {
        while select * from transferOrderQualitySpecloc
        where transferOrderQualitySpecloc.TransferId == this.TransferId
        {
            transferOrderQualitySpec.MinRange           = transferOrderQualitySpecloc.MinRange;
            transferOrderQualitySpec.MaxRange           = transferOrderQualitySpecloc.MaxRange;
            transferOrderQualitySpec.AdjustmentType     = transferOrderQualitySpecloc.AdjustmentType;
            transferOrderQualitySpec.Increment          = transferOrderQualitySpecloc.Increment;
            transferOrderQualitySpec.FixedValue         = transferOrderQualitySpecloc.FixedValue;
            transferOrderQualitySpec.SubGroupID         = transferOrderQualitySpecloc.SubGroupID;
            transferOrderQualitySpec.InventTransId      = this.InventTransId;
            transferOrderQualitySpec.TransferId         = this.TransferId;
            transferOrderQualitySpec.GroupID            = transferOrderQualitySpecloc.GroupID;
            transferOrderQualitySpec.GroupDescription   = transferOrderQualitySpecloc.GroupDescription;
            transferOrderQualitySpec.SubGroupDescription= transferOrderQualitySpecloc.SubGroupDescription;
            transferOrderQualitySpec.insert();
        }
    }

    next insert();


}
